const setupAllDynamicChoices=()=>{document.querySelectorAll("select[data-api]").forEach(async e=>{const t=e.dataset.api,a=e.dataset.params,s=a?JSON.parse(a):{},o=new Choices(e,{searchEnabled:!0,removeItemButton:!1,placeholderValue:"Επιλέξτε...",searchPlaceholderValue:"Αναζήτηση...",shouldSort:!1,loadingText:"Φόρτωση..."});let c=1,r="",n=!0,l=!1;async function loadData({reset:e=!1}={}){if(!l&&n){l=!0;try{const a=new URL(t,window.location.origin);a.searchParams.set("search",r),a.searchParams.set("page",c);for(const[e,t]of Object.entries(s))a.searchParams.set(e,t);const l=await fetch(a),{items:i,hasMore:d}=await l.json();e&&(o.clearChoices(),c=1),o.setChoices(i,"value","label",!1),c++,n=d}catch(e){console.error("Σφάλμα κατά τη φόρτωση:",e)}finally{l=!1}}}e.addEventListener("search",async e=>{r=e.detail.value,c=1,n=!0,await loadData({reset:!0})}),e.addEventListener("change",()=>{const e=o.getValue(),t=Array.isArray(e)?e[0]:e;if(t?.customProperties){const{kodikos:e,apo:a,eos:s}=t.customProperties,o=document.getElementById("info");o&&(o.innerHTML=`\n            <strong>Κωδικός:</strong> ${e||""}<br>\n            <strong>Από:</strong> ${a?new Date(a).toLocaleDateString():"-"}<br>\n            <strong>Έως:</strong> ${s?new Date(s).toLocaleDateString():"-"}`,o.style.display="block")}}),await loadData(),(()=>{const t=e.closest(".choices"),a=new MutationObserver(()=>{const e=t?.querySelector(".choices__list--dropdown .choices__list");e&&!e.dataset.scrollBound&&(e.dataset.scrollBound="true",e.addEventListener("scroll",async()=>{e.scrollTop+e.clientHeight>=e.scrollHeight-20&&await loadData()}),a.disconnect())});a.observe(t,{childList:!0,subtree:!0})})()})};setupAllDynamicChoices();